const question = $.input.customerQuestion || '';
const company = $.input.companyName || '';
const searchQuery = company ? company + ' ' + question : question;
const keywords = question.split(' ').filter(w => w.length > 3).slice(0, 5).join(' ');

return { searchQuery, keywords, question, company };

const results = $.steps.searchKnowledge.response.results || $.steps.searchKnowledge.response.data || [];
let compiled = '';
let sourceCount = 0;
const sources = [];

results.slice(0, 8).forEach((r, i) => {
  compiled += '=== SOURCE ' + (i + 1) + ' ===\n';
  compiled += 'Title: ' + (r.title || 'N/A') + '\n';
  compiled += 'URL: ' + (r.url || '') + '\n';
  compiled += 'Content: ' + (r.text || r.content || '').slice(0, 1500) + '\n\n';
  sources.push({ title: r.title || 'Source ' + (i + 1), url: r.url || '' });
  sourceCount++;
});

return { compiled, sourceCount, sources };

const d = $.steps.compileKnowledge.output;
const question = $.input.customerQuestion;
const company = $.input.companyName || 'our company';
const tone = $.input.supportTone || 'friendly and professional';

let prompt = 'You are a ' + tone + ' customer support agent for ' + company + '. Answer the following customer question using the knowledge sources provided.\n\n';
prompt += 'CUSTOMER QUESTION: ' + question + '\n\n';
prompt += 'KNOWLEDGE SOURCES (' + d.sourceCount + ' found):\n' + d.compiled + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Answer the question directly and helpfully\n';
prompt += '- Use information from the knowledge sources when relevant\n';
prompt += '- If the sources do not fully answer the question, say what you can and suggest next steps\n';
prompt += '- Be ' + tone + ' in tone\n';
prompt += '- Cite sources where applicable using [Source N] notation\n';
prompt += '- Include follow-up suggestions\n';
prompt += '- Use Slack mrkdwn: *bold* (NOT **bold**), _italic_\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "answer": "the complete support response using Slack mrkdwn",\n';
prompt += '  "confidence": "high|medium|low",\n';
prompt += '  "category": "billing|technical|general|product|account",\n';
prompt += '  "sourcesUsed": [1, 3],\n';
prompt += '  "followUpSuggestions": ["suggested follow-up question 1"],\n';
prompt += '  "escalationNeeded": false,\n';
prompt += '  "escalationReason": ""\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { answer: raw, confidence: 'medium', category: 'general', sourcesUsed: [], followUpSuggestions: [], escalationNeeded: false, escalationReason: '' }; }

const ai = $.steps.parseAI.output;
const question = $.input.customerQuestion;
const sources = $.steps.compileKnowledge.output.sources || [];

const confidenceEmoji = ai.confidence === 'high' ? ':large_green_circle:' : ai.confidence === 'low' ? ':red_circle:' : ':large_yellow_circle:';

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'AI Customer Support Response', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Customer Question:* ' + question } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: confidenceEmoji + ' *Confidence:* ' + (ai.confidence || 'medium') },
  { type: 'mrkdwn', text: '*Category:* ' + (ai.category || 'general') }
] });

if (ai.escalationNeeded) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ':rotating_light: *Escalation Needed:* ' + (ai.escalationReason || 'This requires human attention') } });
}

blocks.push({ type: 'divider' });

const answer = (ai.answer || 'No response generated.').slice(0, 2900);
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: answer } });

if (ai.sourcesUsed && ai.sourcesUsed.length > 0) {
  blocks.push({ type: 'divider' });
  let srcText = '*Sources Referenced:*\n';
  ai.sourcesUsed.forEach(idx => {
    const src = sources[idx - 1];
    if (src) {
      srcText += '[' + idx + '] <' + src.url + '|' + src.title + '>\n';
    }
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: srcText.slice(0, 1800) } });
}

if (ai.followUpSuggestions && ai.followUpSuggestions.length > 0) {
  blocks.push({ type: 'divider' });
  let fqText = '*Suggested Follow-ups:*\n';
  ai.followUpSuggestions.forEach((q, i) => { fqText += (i + 1) + '. ' + q + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: fqText.slice(0, 1800) } });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Exa + Claude AI | One CLI' }] });

const fallback = 'Support Response [' + (ai.confidence || 'medium') + ']: ' + (ai.answer || '').slice(0, 100);
return { blocks, fallback };
